import psycopg2
from psycopg2 import sql
import re
import sys

class PostgreSQLExtensionManager:
    ALLOWED_EXTENSIONS = {
        'pg_stat_statements',
        'pg_trgm',
        'btree_gin',
        'btree_gist',
        'citext',
        'cube',
        'dblink',
        'dict_int',
        'earthdistance',
        'fuzzystrmatch',
        'hstore',
        'intarray',
        'isn',
        'lo',
        'ltree',
        'pgcrypto',
        'pgrowlocks',
        'pg_buffercache',
        'pg_freespacemap',
        'pg_prewarm',
        'pg_visibility',
        'postgres_fdw',
        'seg',
        'tablefunc',
        'tcn',
        'tsm_system_rows',
        'tsm_system_time',
        'unaccent',
        'uuid-ossp',
        'xml2'
    }
    
    def __init__(self, host, database, user, password, port=5432):
        self.connection_params = {
            'host': host,
            'database': database,
            'user': user,
            'password': password,
            'port': port
        }
        self.conn = None
        self.cursor = None
    
    def connect(self):
        try:
            self.conn = psycopg2.connect(**self.connection_params)
            self.cursor = self.conn.cursor()
            print(f"Connected to database: {self.connection_params['database']}")
            return True
        except psycopg2.Error as e:
            print(f"Error connecting to database: {e}")
            return False
    
    def disconnect(self):
        if self.cursor:
            self.cursor.close()
        if self.conn:
            self.conn.close()
            print("Disconnected from database")
    
    def validate_extension_name(self, extension_name):
        if not extension_name:
            return False, "Extension name cannot be empty"
        
        if not re.match(r'^[a-z0-9_-]+$', extension_name):
            return False, "Extension name contains invalid characters. Only lowercase letters, numbers, hyphens, and underscores are allowed"
        
        if extension_name not in self.ALLOWED_EXTENSIONS:
            return False, f"Extension '{extension_name}' is not in the allowed list. Please contact administrator to add it to the whitelist"
        
        return True, "Valid"
    
    def list_installed_extensions(self):
        try:
            query = sql.SQL("SELECT extname, extversion FROM pg_extension ORDER BY extname")
            self.cursor.execute(query)
            extensions = self.cursor.fetchall()
            
            if extensions:
                print("\nInstalled Extensions:")
                print("-" * 50)
                for ext_name, ext_version in extensions:
                    print(f"{ext_name:<30} {ext_version}")
            else:
                print("No extensions installed")
            
            return extensions
        except psycopg2.Error as e:
            print(f"Error listing extensions: {e}")
            return []
    
    def list_available_extensions(self):
        try:
            query = sql.SQL("SELECT name, default_version, comment FROM pg_available_extensions ORDER BY name")
            self.cursor.execute(query)
            extensions = self.cursor.fetchall()
            
            if extensions:
                print("\nAvailable Extensions:")
                print("-" * 80)
                for name, version, comment in extensions:
                    comment_str = comment[:50] if comment else "No description"
                    print(f"{name:<25} {version:<15} {comment_str}")
            
            return extensions
        except psycopg2.Error as e:
            print(f"Error listing available extensions: {e}")
            return []
    
    def install_extension(self, extension_name, schema=None, cascade=False):
        is_valid, message = self.validate_extension_name(extension_name)
        
        if not is_valid:
            print(f"Validation failed: {message}")
            return False
        
        try:
            query_parts = [sql.SQL("CREATE EXTENSION IF NOT EXISTS"), sql.Identifier(extension_name)]
            
            if schema:
                if not re.match(r'^[a-z0-9_]+$', schema):
                    print("Invalid schema name")
                    return False
                query_parts.extend([sql.SQL("SCHEMA"), sql.Identifier(schema)])
            
            if cascade:
                query_parts.append(sql.SQL("CASCADE"))
            
            query = sql.SQL(" ").join(query_parts)
            
            self.cursor.execute(query)
            self.conn.commit()
            
            print(f"Successfully installed extension: {extension_name}")
            return True
            
        except psycopg2.Error as e:
            self.conn.rollback()
            print(f"Error installing extension '{extension_name}': {e}")
            return False
    
    def uninstall_extension(self, extension_name, cascade=False):
        is_valid, message = self.validate_extension_name(extension_name)
        
        if not is_valid:
            print(f"Validation failed: {message}")
            return False
        
        try:
            query_parts = [sql.SQL("DROP EXTENSION IF EXISTS"), sql.Identifier(extension_name)]
            
            if cascade:
                query_parts.append(sql.SQL("CASCADE"))
            
            query = sql.SQL(" ").join(query_parts)
            
            self.cursor.execute(query)
            self.conn.commit()
            
            print(f"Successfully uninstalled extension: {extension_name}")
            return True
            
        except psycopg2.Error as e:
            self.conn.rollback()
            print(f"Error uninstalling extension '{extension_name}': {e}")
            return False
    
    def check_extension_exists(self, extension_name):
        try:
            query = sql.SQL("SELECT EXISTS(SELECT 1 FROM pg_extension WHERE extname = %s)")
            self.cursor.execute(query, (extension_name,))
            exists = self.cursor.fetchone()[0]
            return exists
        except psycopg2.Error as e:
            print(f"Error checking extension: {e}")
            return False


def print_menu():
    print("\n" + "="*60)
    print("PostgreSQL Extension Manager")
    print("="*60)
    print("1. List installed extensions")
    print("2. List available extensions")
    print("3. Install extension")
    print("4. Uninstall extension")
    print("5. Check if extension exists")
    print("6. Show allowed extensions")
    print("7. Exit")
    print("="*60)


def main():
    print("PostgreSQL Extension Manager - Secure Version")
    print("-" * 60)
    
    host = input("Enter database host (default: localhost): ").strip() or "localhost"
    database = input("Enter database name: ").strip()
    user = input("Enter database user: ").strip()
    password = input("Enter database password: ").strip()
    port = input("Enter database port (default: 5432): ").strip() or "5432"
    
    try:
        port = int(port)
    except ValueError:
        print("Invalid port number. Using default 5432")
        port = 5432
    
    manager = PostgreSQLExtensionManager(host, database, user, password, port)
    
    if not manager.connect():
        print("Failed to connect to database. Exiting.")
        return
    
    try:
        while True:
            print_menu()
            choice = input("\nEnter your choice (1-7): ").strip()
            
            if choice == '1':
                manager.list_installed_extensions()
            
            elif choice == '2':
                manager.list_available_extensions()
            
            elif choice == '3':
                extension_name = input("Enter extension name to install: ").strip().lower()
                schema = input("Enter schema name (press Enter for default): ").strip() or None
                cascade_input = input("Install with CASCADE? (y/n, default: n): ").strip().lower()
                cascade = cascade_input == 'y'
                
                manager.install_extension(extension_name, schema, cascade)
            
            elif choice == '4':
                extension_name = input("Enter extension name to uninstall: ").strip().lower()
                cascade_input = input("Uninstall with CASCADE? (y/n, default: n): ").strip().lower()
                cascade = cascade_input == 'y'
                
                manager.uninstall_extension(extension_name, cascade)
            
            elif choice == '5':
                extension_name = input("Enter extension name to check: ").strip().lower()
                exists = manager.check_extension_exists(extension_name)
                if exists:
                    print(f"Extension '{extension_name}' is installed")
                else:
                    print(f"Extension '{extension_name}' is not installed")
            
            elif choice == '6':
                print("\nAllowed Extensions:")
                print("-" * 60)
                for ext in sorted(manager.ALLOWED_EXTENSIONS):
                    print(f"  - {ext}")
            
            elif choice == '7':
                print("Exiting...")
                break
            
            else:
                print("Invalid choice. Please enter a number between 1 and 7")
    
    except KeyboardInterrupt:
        print("\n\nInterrupted by user")
    
    finally:
        manager.disconnect()


if __name__ == "__main__":
    main()